<section class="admin-page-head"><div><p class="eyebrow">ATELIER</p><h1>Articole</h1></div><div class="button-row"><a class="admin-button secondary" href="<?= e(url('/admin/atelier/calendar')) ?>">Calendar editorial</a><a class="admin-button" href="<?= e(url('/admin/atelier/creare')) ?>">Articol nou</a></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><section class="admin-panel"><form class="admin-filters" method="get"><input type="search" name="q" value="<?= e($q) ?>" placeholder="Titlu sau slug"><select name="status"><option value="">Toate statusurile</option><?php foreach(['draft','in_review','scheduled','published','archived'] as $value): ?><option <?= $status===$value?'selected':'' ?>><?= e($value) ?></option><?php endforeach; ?></select><button class="admin-button" type="submit">Filtrează</button><a href="<?= e(url('/admin/atelier/taxonomii')) ?>">Taxonomii</a></form><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Articol</th><th>Autor</th><th>Status</th><th>Publicare</th><th>Revizii</th><th>Acțiuni</th></tr></thead><tbody><?php foreach($items as $item): ?><tr><td><a href="<?= e(url('/admin/atelier/'.$item['id'].'/edit')) ?>"><strong><?= e($item['title']) ?></strong></a><small>/atelier/<?= e($item['slug']) ?></small></td><td><?= e($item['author_name']?:'—') ?></td><td><span class="status-pill <?= $item['status']==='published'?'success':'' ?>"><?= e($item['status']) ?></span></td><td><?= $item['scheduled_at']?date('d.m.Y H:i',strtotime($item['scheduled_at'])):($item['published_at']?date('d.m.Y',strtotime($item['published_at'])):'—') ?></td><td><a href="<?= e(url('/admin/atelier/'.$item['id'].'/revisions')) ?>"><?= (int)$item['revision_count'] ?></a></td><td><div class="admin-table-actions"><a class="admin-icon-action" href="<?= e(url('/admin/atelier/'.$item['id'].'/edit')) ?>" title="Editează articolul" aria-label="Editează <?= e($item['title']) ?>"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M4 20h4l11-11-4-4L4 16v4zM13.5 6.5l4 4"/></svg></a><form method="post" action="<?= e(url('/admin/atelier/'.$item['id'].'/sterge')) ?>" data-confirm-delete data-confirm-message="Articolul va fi arhivat și scos din zona publică."><?= csrf_field() ?><button class="admin-icon-action danger" type="submit" title="Șterge articolul" aria-label="Șterge <?= e($item['title']) ?>"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M4 7h16M9 7V4h6v3m-9 0 1 13h10l1-13M10 11v5m4-5v5"/></svg></button></form></div></td></tr><?php endforeach; ?></tbody></table></div></section>